class IntentSenderRequestCompat(val intentSender: android.content.IntentSender)

class IntentSenderRequestContractCompat :
    ActivityResultContracts.StartIntentSenderForResult() {
    override fun createIntent(context: Context, input: IntentSenderRequestCompat): Intent {
        return androidx.activity.result.IntentSenderRequest.Builder(input.intentSender).build().let {
            super.createIntent(context, it)
        }
    }
}

